import SwiftUI

struct UserInputForm: View {
    @State private var username = ""
    @State private var submitted = false

    var body: some View {
        Form {
            TextField("Username", text: $username)
            Button("Submit") { submitted = true }
            if submitted {
                Text("Welcome, \(username)!")
            }
        }
        .padding()
    }
}
